'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useSelection } from '@/context/SelectionContext';
import styles from './chat.module.css';
import { ArrowLeft, Send, ShieldCheck } from 'lucide-react';

export default function CoachChat({ params }: { params: { id: string } }) {
    const { selectedCoach } = useSelection();
    const [messages, setMessages] = useState<{ id: string; sender: 'user' | 'coach'; text: string; time: string }[]>([
        { id: '1', sender: 'coach', text: `Hej! Jag ser att du matchades med mig. Hur mår du idag?`, time: '14:20' }
    ]);
    const [input, setInput] = useState('');
    const scrollRef = useRef<HTMLDivElement>(null);
    const router = useRouter();

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const handleSend = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            sender: 'user',
            text: input,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        }]);
        setInput('');
    };

    return (
        <div className={styles.container}>
            <header className={styles.header}>
                <div className="container flex items-center gap-md">
                    <button onClick={() => router.back()} className={styles.backBtn}><ArrowLeft size={20} /></button>
                    <img src={selectedCoach?.avatar} alt={selectedCoach?.name} className={styles.avatar} />
                    <div>
                        <h2 className={styles.name}>{selectedCoach?.name || 'Din coach'}</h2>
                        <p className={styles.status}>Online</p>
                    </div>
                </div>
            </header>

            <div className={styles.messages} ref={scrollRef}>
                <div className={styles.disclaimer}>
                    <ShieldCheck size={16} />
                    Det här är ett privat samtal mellan dig och din coach.
                </div>
                {messages.map(msg => (
                    <div key={msg.id} className={`${styles.messageWrapper} ${styles[msg.sender]}`}>
                        <div className={styles.bubble}>
                            {msg.text}
                            <span className={styles.time}>{msg.time}</span>
                        </div>
                    </div>
                ))}
            </div>

            <div className={styles.inputArea}>
                <div className="container">
                    <form onSubmit={handleSend} className={styles.form}>
                        <input
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder="Skriv ett meddelande till din coach..."
                            className={styles.input}
                        />
                        <button type="submit" className={styles.sendBtn}><Send size={20} /></button>
                    </form>
                    <div className={styles.bookingBar}>
                        Känns det rätt? <button onClick={() => router.push(`/book/${params.id}`)} className={styles.bookInChat}>Boka ett samtal</button>
                    </div>
                </div>
            </div>
        </div>
    );
}
